import { queue, task, wait } from "@trigger.dev/sdk/v3";

const trial_id = "concurrency_controlled_queue__VWZ9meg";

// Define a named queue with a concurrency limit of 1
const criticalQueue = queue({
  name: `critical-queue-${trial_id}`,
  concurrencyLimit: 1,
});

// Define the critical task that uses the named queue
export const criticalTask = task({
  id: `criticalTask-${trial_id}`,
  queue: criticalQueue,
  run: async (payload: Record<string, unknown>) => {
    console.log(`[${new Date().toISOString()}] criticalTask started`, payload);

    // Simulate work by waiting for 5 seconds
    await wait.for({ seconds: 5 });

    console.log(`[${new Date().toISOString()}] criticalTask completed`);

    return {
      status: "completed",
      trialId: trial_id,
    };
  },
});
